// Fidget Cube — the classic six-sided desk fidget. A soft rounded cube where
// every face carries a different tactile toy: a die-5 of click buttons, a
// recessed dial with a knurled knob, a slot-and-bar switch, a joystick nub on
// a dished circle, a gear spinning in a recessed window, and a smooth worry
// dish. Built from a hull-rounded cube base, then each face adds raised accents
// (cylinders/spheres/bars overlapping the body) and subtracts shallow recesses.
const { Manifold } = api;

const p = api.params({
  size:    { type: 'number', default: 24, min: 18, max: 40, step: 1,   unit: 'mm', label: 'Cube size' },
  round:   { type: 'number', default: 3,  min: 0,  max: 6,  step: 0.5, unit: 'mm', label: 'Edge rounding' },
  feature: { type: 'number', default: 1,  min: 0.6, max: 1.5, step: 0.05, label: 'Feature scale' },
  body:    { type: 'color',  default: '#3a4252', label: 'Body color' },
});

const S = p.size;
const h = S / 2;                                   // half-extent → faces at ±h
const r = Math.min(p.round, S / 2 - 0.5);          // corner radius, kept sane
const F = p.feature;                               // feature multiplier

// Accent palette
const RED    = '#ff5470';
const YELLOW = '#ffd23f';
const GREEN  = '#2ee6a6';
const BLUE   = '#22b3ff';

// --- Rounded-cube base: hull of 8 inset corner spheres -----------------------
let base;
if (r > 0.2) {
  const c = h - r;                                 // sphere centers inset by r
  const corners = [];
  for (const sx of [-1, 1]) for (const sy of [-1, 1]) for (const sz of [-1, 1]) {
    corners.push(Manifold.sphere(r).translate([sx * c, sy * c, sz * c]));
  }
  base = Manifold.hull(corners);
} else {
  base = Manifold.cube([S, S, S], true);
}

// Collect raised accent parts (named for color) plus a list of recess cutters.
const raised = [];   // { name, shape, color }
const cuts   = [];   // Manifold cutters subtracted from the body

// Helper: a disc lying flat then oriented & pushed onto a face.
// face is one of '+x','-x','+y','-y','+z','-z'. `into` = how deep below the
// surface the geometry's reference sits; we model each feature in +Z-up local
// space (sitting on the z=0 plane) and then move it to the chosen face.
function toFace(shape, face) {
  // shape is built in local space with the face plane at z=0, outward = +Z.
  switch (face) {
    case '+z': return shape.translate([0, 0, h]);
    case '-z': return shape.rotate([180, 0, 0]).translate([0, 0, -h]);
    case '+y': return shape.rotate([-90, 0, 0]).translate([0, h, 0]);
    case '-y': return shape.rotate([90, 0, 0]).translate([0, -h, 0]);
    case '+x': return shape.rotate([0, 90, 0]).translate([h, 0, 0]);
    case '-x': return shape.rotate([0, -90, 0]).translate([-h, 0, 0]);
  }
}

// ============================================================================
// FACE +Z — BUTTONS (a die's 5: four corners + center, raised click dots)
// ============================================================================
{
  const dotR = 2.2 * F;
  const dotH = 1.6 * F;          // raised height above the surface
  const off  = h * 0.42;         // corner offset
  // dot sits on z=0 plane, overlaps body by 1mm
  const dot = Manifold.cylinder(dotH + 1, dotR, dotR * 0.85).translate([0, 0, -1]);
  const positions = [[-off, -off], [off, -off], [-off, off], [off, off], [0, 0]];
  const colors = [RED, BLUE, GREEN, YELLOW, RED];
  positions.forEach((xy, i) => {
    const d = toFace(dot.translate([xy[0], xy[1], 0]), '+z');
    raised.push({ name: 'btn' + i, shape: d, color: colors[i] });
  });
  // two shallow recessed rings around the off-diagonal dots for "pressed" look
  const ring = Manifold.cylinder(1.2, dotR + 1.1, dotR + 1.1).translate([0, 0, -0.6]);
  for (const xy of [[off, -off], [-off, off]]) {
    cuts.push(toFace(ring.translate([xy[0], xy[1], 0]), '+z'));
  }
}

// ============================================================================
// FACE -Z — DIAL (shallow recessed disc + raised knurled knob in the center)
// ============================================================================
{
  const wellR = h * 0.62;
  const well  = Manifold.cylinder(2.2, wellR, wellR).translate([0, 0, -1.2]);
  cuts.push(toFace(well, '-z'));
  // central knob
  const knobR = h * 0.34 * F;
  const knob  = Manifold.cylinder(2.6 * F, knobR, knobR * 0.9).translate([0, 0, -1]);
  raised.push({ name: 'dial-knob', shape: toFace(knob, '-z'), color: YELLOW });
  // knurl: a ring of small ridges around the knob
  const teeth = 10;
  const ridge = Manifold.cube([0.9, 1.6, 2.4 * F], true).translate([0, 0, (2.4 * F) / 2 - 1]);
  for (let i = 0; i < teeth; i++) {
    const a = (i / teeth) * Math.PI * 2;
    const rr = knobR + 0.3;
    const t  = ridge.rotate([0, 0, (a * 180) / Math.PI])
                    .translate([Math.cos(a) * rr, Math.sin(a) * rr, 0]);
    raised.push({ name: 'dial-knurl' + i, shape: toFace(t, '-z'), color: BLUE });
  }
}

// ============================================================================
// FACE +Y — SWITCH (a slot recess with a raised toggle bar sitting in it)
// ============================================================================
{
  const slotW = h * 1.05;
  const slotD = h * 0.4;
  const slot  = Manifold.cube([slotW, slotD, 2.4], true).translate([0, 0, -1.2 + 0]);
  // round the slot ends slightly with end-caps
  const cap   = Manifold.cylinder(2.4, slotD / 2, slotD / 2);
  const slotCS = slot
    .add(cap.translate([-slotW / 2, 0, -1.2]))
    .add(cap.translate([slotW / 2, 0, -1.2]));
  cuts.push(toFace(slotCS, '+y'));
  // the toggle bar — a rounded bar offset to one side of the slot
  const barL = slotW * 0.42 * F;
  const bar  = Manifold.cube([barL, slotD * 0.7, 3.0 * F], true)
                 .translate([slotW * 0.18, 0, (3.0 * F) / 2 - 1]);
  raised.push({ name: 'switch-bar', shape: toFace(bar, '+y'), color: RED });
}

// ============================================================================
// FACE -Y — JOYSTICK (raised dome/nub on a small recessed circle)
// ============================================================================
{
  const wellR = h * 0.48;
  const well  = Manifold.cylinder(1.8, wellR, wellR).translate([0, 0, -1]);
  cuts.push(toFace(well, '-y'));
  const stickR = 1.5 * F;
  const stickH = 2.0 * F;
  // root the stick 1.5 below the face so it overlaps the well floor (≥0.5)
  const stick  = Manifold.cylinder(stickH + 1.5, stickR, stickR).translate([0, 0, -1.5]);
  const domeR  = 3.0 * F;
  const dome   = Manifold.sphere(domeR).translate([0, 0, stickH - 0.4]);
  const joystick = stick.add(dome);
  raised.push({ name: 'joystick', shape: toFace(joystick, '-y'), color: GREEN });
}

// ============================================================================
// FACE +X — SPINNER GEAR (recessed window with a small cog inside)
// ============================================================================
{
  const winR = h * 0.6;
  const win  = Manifold.cylinder(2.6, winR, winR).translate([0, 0, -1.4]);
  cuts.push(toFace(win, '+x'));
  // gear: hub + radial teeth, sitting at the bottom of the recess
  const teeth = 8;
  const hubR  = h * 0.34 * F;
  const gearH = 1.8 * F;
  let gear = Manifold.cylinder(gearH, hubR, hubR);
  const tooth = Manifold.cube([2.4, 2.4, gearH], true).translate([0, 0, gearH / 2]);
  for (let i = 0; i < teeth; i++) {
    const a = (i / teeth) * Math.PI * 2;
    gear = gear.add(tooth.rotate([0, 0, (a * 180) / Math.PI])
                         .translate([Math.cos(a) * hubR, Math.sin(a) * hubR, 0]));
  }
  // center bore so it reads as a cog
  gear = gear.subtract(Manifold.cylinder(gearH + 2, hubR * 0.35, hubR * 0.35).translate([0, 0, -1]));
  // drop the gear into the recess so its base overlaps the well floor (≥0.5)
  // and its top sits recessed just below the face plane
  gear = gear.translate([0, 0, -2.0]);
  raised.push({ name: 'gear', shape: toFace(gear, '+x'), color: BLUE });
}

// ============================================================================
// FACE -X — WORRY STONE (smooth dished circular recess)
// ============================================================================
{
  // a large shallow sphere subtracted from the face → a soft thumb dish
  const dishR = h * 1.15;          // big sphere, only a shallow cap intersects
  const depth = 2.2;               // how deep the dish bites in
  const dish  = Manifold.sphere(dishR).translate([0, 0, dishR - depth]);
  cuts.push(toFace(dish, '-x'));
}

// --- Assemble: subtract all recesses from the body, then union accents -------
let bodyShape = base;
for (const c of cuts) bodyShape = bodyShape.subtract(c);

const parts = [{ name: 'body', shape: bodyShape, color: p.body }, ...raised];
return api.labeledUnion(parts);

